const raw = $input.first()?.json || {};
const body = raw.body || {};
const data = raw.chat_id ? raw : (body.chat_id ? body : raw);
const chat_id = Number(data.chat_id ?? 0);
return [{
  json: {
    chat_id,
    sessionId: String(chat_id),
    text: String(data.text ?? '').trim(),
    _meta: { source: 'NN_03-C_Agent', timestamp: new Date().toISOString(), version: '3.0.0' }
  }
}];

const chatIdStr = String($json.chat_id ?? '');
const chat_id_valid = chatIdStr.length > 0 && [...chatIdStr].every(c => c >= '0' && c <= '9');
const text = String($('Input_Clean').first().json.text ?? '').trim();
const text_valid = text.length > 2 && text.length < 500;
return [{ json: { ...$json, isValid: chat_id_valid && text_valid } }];

return [{ json: { success: false, error_code: 'VALIDATION_ERROR',
  error_message: 'chat_id debe ser numérico y text entre 3-499 chars',
  data: null, _meta: { source: 'NN_03-C_Agent', timestamp: new Date().toISOString(), version: '3.0.0' }
} }];

const textLower = String($('Input_Clean').first().json.text || '').toLowerCase();
const PROFANITY = /\b(conchetumare|ctm|culiao|qliao|pichula|tula|zorra|maraco|maricón|maricon|puta|mierda|fuck|shit|asshole|bitch|bastard|motherfucker|dick|cunt|pussy|prick|estúpido|estupido|idiota|imbécil|imbecil|gilipollas|huevon|weon)\b/i;
const INJECTION = ['ignore all previous instructions','disregard all rules','system prompt','jailbreak','dan mode','olvida todas las instrucciones'];
const OFFTOPIC  = ['escribe un poema','write a poem','cuéntame un cuento','tell me a story','genera código','create code','hackear','hacking'];
let isBlocked = PROFANITY.test(textLower);
if (!isBlocked) for (const p of INJECTION) if (textLower.includes(p)) { isBlocked = true; break; }
if (!isBlocked) for (const p of OFFTOPIC)  if (textLower.includes(p)) { isBlocked = true; break; }
return [{ json: { ...$json, isBlocked } }];

return [{ json: { success: false, error_code: 'SECURITY_BLOCKED',
  error_message: 'Mensaje bloqueado por reglas de seguridad',
  data: null, _meta: { source: 'NN_03-C_Agent', timestamp: new Date().toISOString(), version: '3.0.0' }
} }];

const input = $input.first()?.json || {};
// El AI Agent devuelve su respuesta en .output o .text
let aiResp = input.output || input.text || input.ai_response || '';
if (typeof aiResp === 'string') aiResp = aiResp.replace(/^[\"']|[\"']$/g, '').trim();
if (!aiResp) aiResp = 'Lo siento, no pude procesar tu solicitud en este momento.';

let chatId = 0;
try { chatId = $('Input_Clean').first().json.chat_id || 0; } catch(e) {}

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      chat_id:      chatId,
      ai_response:  aiResp
    },
    _meta: {
      source:    'NN_03-C_Agent',
      timestamp: new Date().toISOString(),
      version:   '3.0.0'
    }
  }
}];

const input = $input.first()?.json || {};
// Fix v2.2: leer error del json, NO de $input.params.error (API inexistente)
const errorCode    = input.error_code    || input.code    || 'EXECUTION_ERROR';
const errorMessage = input.error_message || input.message || 'Error desconocido';

return [{
  json: {
    success: false,
    error_code:    errorCode,
    error_message: errorMessage,
    data: null,
    _meta: {
      source:    'NN_03-C_Agent',
      timestamp: new Date().toISOString(),
      version:   '3.0.0'
    }
  }
}];
